import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { getChansons, deleteChanson } from '../api/chansonService';
import { getAlbums } from '../api/albumService';

export default function ChansonsList() {
  const [chansons, setChansons] = useState([]);
  const [albums, setAlbums] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = () => {
    setLoading(true);
    Promise.all([getChansons(), getAlbums()])
      .then(([chansonsRes, albumsRes]) => {
        setChansons(chansonsRes.data || []);
        setAlbums(albumsRes.data || []);
      })
      .catch(() => {
        setChansons([]);
        setAlbums([]);
      })
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    fetchData();
  }, []);

  const findAlbumTitle = (albumId) => {
    const album = albums.find((item) => item.id === albumId);
    return album ? album.titre : `Album ${albumId}`;
  };

  const handleDelete = (id) => {
    if (!window.confirm('Supprimer cette chanson ?')) return;
    deleteChanson(id).then(() => fetchData());
  };

  return (
    <div>
      <div className="d-flex align-items-center justify-content-between mb-4">
        <div>
          <h1 className="h3 mb-0">Chansons</h1>
          <p className="text-muted mb-0">Toutes les pistes musicales disponibles dans la bibliothèque.</p>
        </div>
        <Link className="btn btn-primary" to="/chansons/create">
          Créer une chanson
        </Link>
      </div>

      {loading ? (
        <div className="alert alert-secondary">Chargement des chansons...</div>
      ) : chansons.length === 0 ? (
        <div className="alert alert-warning">Aucune chanson enregistrée.</div>
      ) : (
        <div className="table-responsive">
          <table className="table table-hover align-middle">
            <thead className="table-light">
              <tr>
                <th>Titre</th>
                <th>Album</th>
                <th>Fichier audio</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {chansons.map((chanson) => (
                <tr key={chanson.id}>
                  <td>
                    <Link to={`/chansons/${chanson.id}`} className="fw-bold">
                      {chanson.titre || `Chanson ${chanson.id}`}
                    </Link>
                    <div className="text-muted small">ID: {chanson.id}</div>
                  </td>
                  <td>{findAlbumTitle(chanson.albumId)}</td>
                  <td>
                    {chanson.fichierAudio ? (
                      <span className="badge bg-success">Prête</span>
                    ) : (
                      <span className="badge bg-secondary">Aucun fichier</span>
                    )}
                  </td>
                  <td>
                    <Link className="btn btn-sm btn-outline-secondary me-2" to={`/chansons/${chanson.id}/edit`}>
                      Modifier
                    </Link>
                    <button className="btn btn-sm btn-danger" onClick={() => handleDelete(chanson.id)}>
                      Supprimer
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
